     1	// Re-export the Rhino-generated model schemas as friendly, fully-required types.
     2	// The generator emits everything as optional (`field?:`) because the source is
     3	// an OpenAPI-ish schema; we tighten them here for nicer DX on the consumer side.
     4	import type { components } from './rhino.d.ts';
     5	
     6	type Required<T> = { [K in keyof T]-?: T[K] };
     7	
     8	export type Organization = Required<components['schemas']['Organization']>;
     9	export type Role         = Required<components['schemas']['Role']>;
    10	export type User         = Required<components['schemas']['User']>;
    11	export type UserRole     = Required<components['schemas']['UserRole']>;
    12	export type Comment      = Required<components['schemas']['Comment']>;
    13	export type Label        = Required<components['schemas']['Label']>;
    14	export type Project      = Required<components['schemas']['Project']>;
    15	export type Task         = Required<components['schemas']['Task']>;
    16	
    17	// Convenience types for relations populated via ?include=
    18	export type ProjectWithTasks    = Project & { tasks?: Task[] };
    19	export type TaskWithAssignee    = Task & { assignee?: User };
    20	export type CommentWithAuthor   = Comment & { user?: User };
    21	
    22	// Permission slug type — every resource exposes 5 CRUD verbs.
    23	export type ResourceSlug = 'projects' | 'tasks' | 'comments' | 'labels' | 'users';
    24	export type ActionSlug   = 'index' | 'show' | 'store' | 'update' | 'destroy' | 'trashed' | 'restore' | 'force-delete';
    25	export type PermissionSlug = `${ResourceSlug}.${ActionSlug}` | '*' | `${ResourceSlug}.*`;
